def binary_search(arr, target):
    """Search for target in a sorted array. Returns index or -1 if not found."""
    left, right = 0, len(arr) - 1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

# Example:
nums = [1, 3, 5, 7, 9, 11, 13]
print(binary_search(nums, 7))   # Output: 3
print(binary_search(nums, 4))   # Output: -1
